patterns.example:
kind: Secret
data:
  config.yaml: {{ .Values.config | toYaml | b64enc }}

{{- if .Values.rbac.create }}
apiVersion: rbac.authorization.k8s.io/v1
kind: Role
{{- end }}

code_examples.code:
# In statefulset.yaml env section:
{{- if .Values.myFeature.enabled }}
- name: MY_FEATURE_URL
  value: {{ .Values.myFeature.url | quote }}
{{- end }}

# In _helpers.tpl, extend benthos-collector.args to pass --my-feature-flag
# when .Values.myFeature.enabled is true — keep all arg logic in the helper.

# In deployment.yaml, follow the existing component block pattern:
- name: {{ include "openmeter.componentName" (list . "my-worker") }}
  replicas: {{ .Values.myWorker.replicaCount }}
  template:
    metadata:
      annotations:
        checksum/config: {{ include (print $.Template.BasePath "/configmap.yaml") . | sha256sum }}
      labels: {{- include "openmeter.componentLabels" (list . "my-worker") | nindent 8 }}
    spec:
      containers:
        - image: {{ .Values.image.repository }}:{{ .Values.image.tag | default .Chart.AppVersion }}
          args: ["my-worker"]
          volumeMounts:
            - name: config
              mountPath: /etc/openmeter
# Add myWorker.replicaCount: 1 in values.yaml
